sp_widget.client_script:
function($scope, $location) {
    var c = this;

    c.navigateTo = function(path) {
        $location.path(path);
    };

    c.orderService = function(itemId) {
        $location.path('/sc_cat_item').search({sys_id: itemId});
    };
}

sp_widget.css:
.platform-dashboard {
    padding: var(--carbon-spacing-05);
}

.dashboard-header {
    margin-bottom: var(--carbon-spacing-06);
}

.dashboard-header h1 {
    color: var(--carbon-text-01);
    font-size: 2rem;
    margin-bottom: var(--carbon-spacing-03);
    display: flex;
    align-items: center;
    gap: var(--carbon-spacing-03);
}

.dashboard-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
    gap: var(--carbon-spacing-05);
    margin-bottom: var(--carbon-spacing-06);
}

.dashboard-card {
    background: var(--carbon-ui-01);
    border: 1px solid var(--carbon-ui-03);
    border-radius: 4px;
    padding: var(--carbon-spacing-05);
}

.dashboard-card h2 {
    color: var(--carbon-text-01);
    font-size: 1.25rem;
    margin-bottom: var(--carbon-spacing-04);
    display: flex;
    align-items: center;
    gap: var(--carbon-spacing-03);
}

.quick-links {
    display: flex;
    flex-direction: column;
    gap: var(--carbon-spacing-03);
}

.quick-link {
    display: flex;
    align-items: center;
    gap: var(--carbon-spacing-03);
    padding: var(--carbon-spacing-03);
    background: var(--carbon-ui-background);
    border: 1px solid var(--carbon-ui-03);
    border-radius: 4px;
    cursor: pointer;
    transition: all 0.2s ease;
    text-decoration: none;
    color: var(--carbon-text-01);
}

.quick-link:hover {
    border-color: var(--carbon-interactive-01);
    background: var(--carbon-hover-ui);
}

.metric-card {
    background: var(--carbon-ui-background);
    border: 1px solid var(--carbon-ui-03);
    border-radius: 4px;
    padding: var(--carbon-spacing-04);
    text-align: center;
}

.metric-value {
    font-size: 2rem;
    font-weight: 600;
    color: var(--carbon-text-01);
}

.metric-label {
    font-size: 0.875rem;
    color: var(--carbon-text-02);
    margin-top: var(--carbon-spacing-02);
}

sp_widget.script:
(function() {
    data.user = gs.getUser();
    data.userName = data.user.getDisplayName();

    // Platform metrics (mock data - replace with actual queries)
    data.metrics = {
        activeInfrastructure: 45,
        automationJobs: 128,
        resourceUtilization: 73,
        pendingChanges: 8
    };
})();
